#!/bin/bash
# AEON INTELLIGENCE PIPELINE: Digital Signal Snatcher
# Bifurcates IQ stream into Visual Manifold and Digital Resolver.

FREQ=$1
if [ -z "$FREQ" ]; then
    FREQ="915000000"
fi

echo "[RESOLVER] Activating Distributed Mesh on $FREQ Hz..." >&2

# 1. Visual + Digital Pipeline
# We use 'tee' to send data to both the waterfall generator and the protocol decoder.
rtl_sdr -f "$FREQ" -s 256000 -g 0 - 2>/dev/null | \
    tee >(./target/release/iq-waterfall-frame --input - --output spectrum_waterfall.frame --iq-rate 256000 --center-hz "$FREQ" --fft-size 512 --rows 48 --source-id auto_bridge --continuous) | \
    rtl_433 -r - -M level -F json | ./target/release/iot-residue-collector &

# 2. NOAA APT Imaging Aggregation
if [[ "$FREQ" == *"137"* ]]; then
    echo "[RESOLVER] Satellite Band detected. Starting Imaging Aggregator..." >&2
    ./target/release/noaa-apt-synth-frame &
fi

wait
